async function seed() {
  console.log(`Seeding ${products.length} products...`);

  const { data, error } = await supabase
    .from("products")
    .insert(products)
    .select("id, name");

  if (error) {
    console.error("Seed failed:", error.message);
  } else {
    console.log(`Seeded ${data.length} products successfully!`);
  }
}

seed();
